#!/usr/bin/env python3
"""Apply the Patreon tier-truth fix (commit 0316f60) to the poller IN PLACE.
Self-verifying: each hunk must match exactly once per file or it aborts.
Usage: python3 patch-tier-truth.py /abs/path/to/lg-patreon-stripe-poller
"""
import sys, os
ROOT = sys.argv[1] if len(sys.argv)>1 else '.'
TARGETS = {
  'src/Patreon/PatreonSourceReader.php': 'PatreonSourceReader.php',
  'src/RoleSourceWriter.php': 'RoleSourceWriter.php',
}
HUNKS = {"PatreonSourceReader.php": [["final class PatreonSourceReader\n{\n    /**\n     * @return array{source:string,tier:string,tier_id:?string}|null\n     *   null = not Patreon-managed; otherwise the source record.\n     */\n    public static function readForUser( int $wpUserId ): ?array\n    {\n", "final class PatreonSourceReader\n{\n    /**\n     * @return array{source:string,tier:?string,tier_id:?string}|null\n     *   null = not Patreon-managed; otherwise the source record. 'tier' may be\n     *   null = patreon-managed but no active paid tier (lapsed / declined / free).\n     */\n    public static function readForUser( int $wpUserId ): ?array\n    {\n"], ["            return null;\n        }\n\n        $user = get_userdata( $wpUserId );\n        if ( ! $user ) {\n            return null;\n        }\n\n        $roles = (array) $user->roles;\n        $tier  = 'looth1';\n        foreach ( [ 'looth3', 'looth2', 'looth1' ] as $r ) {\n            if ( in_array( $r, $roles, true ) ) {\n                $tier = $r;\n                break;\n            }\n        }\n\n        $tierId = get_user_meta( $wpUserId, 'lgpo_patreon_tier_id', true );\n\n        return [\n            'source'  => 'patreon',\n            'tier'    => $tier,\n            'tier_id' => is_string( $tierId ) && $tierId !== '' ? $tierId : null,\n        ];\n    }\n}\n", "            return null;\n        }\n\n        $tierId = get_user_meta( $wpUserId, 'lgpo_patreon_tier_id', true );\n        $tierId = is_string( $tierId ) && $tierId !== '' ? $tierId : null;\n\n        // Derive the tier from the Patreon API truth the sweep persists — the\n        // entitled tier_id mapped through lgpo_tier_map — NOT from $user->roles.\n        // Reading the current WP role was circular: the Arbiter would only ever\n        // hear back the role the member already had, so an upgrade could never\n        // apply (it could only ever confirm the status quo). A patreon-managed\n        // member with no mapped PAID tier (lapsed, declined, or free looth1)\n        // resolves to null, so the Arbiter performs a real downgrade instead of\n        // pinning the member at their current role.\n        $tier = null;\n        if ( $tierId !== null ) {\n            $map = get_option( 'lgpo_tier_map', [] );\n            if ( is_array( $map ) && isset( $map[ $tierId ] ) ) {\n                $mapped = (string) $map[ $tierId ];\n                // Only paid Patreon tiers are asserted by this source. looth1 is\n                // the free floor (treated as null); looth4 is comp/manual and is\n                // never granted via Patreon — leave it to its own source.\n                if ( $mapped === 'looth2' || $mapped === 'looth3' ) {\n                    $tier = $mapped;\n                }\n            }\n        }\n\n        return [\n            'source'  => 'patreon',\n            'tier'    => $tier,\n            'tier_id' => $tierId,\n        ];\n    }\n}\n"]], "RoleSourceWriter.php": [["            $out[ (string) $row['source'] ] = $row['tier'] !== null ? (string) $row['tier'] : null;\n        }\n\n        // Merge Patreon adapter's view. Only present when LGPO owns the\n        // user (payment_source=patreon). PatreonSourceReader returns null\n        // otherwise — Stripe-owned users are never given a patreon row.\n        // Persisted lg_role_sources rows for 'patreon' (legacy / from\n        // earlier sessions) are overwritten by the live read so the\n        // Arbiter sees current truth.\n        $patreon = PatreonSourceReader::readForUser( $wpUserId );\n        if ( $patreon !== null ) {\n            $out['patreon'] = (string) $patreon['tier'];\n        }\n\n        return $out;\n", "            $out[ (string) $row['source'] ] = $row['tier'] !== null ? (string) $row['tier'] : null;\n        }\n\n        // Surface a Patreon source ONLY when the sweep has not already\n        // persisted one. The sweep is the authority for Patreon: it writes the\n        // API-derived tier to the lg_role_sources 'patreon' row\n        // (RoleSourceWriter::report) on every poll. We must NOT overwrite that\n        // row here — the old code re-derived 'patreon' from the member's\n        // CURRENT WP role, which was circular and blocked upgrades (the Arbiter\n        // only ever heard back the role it had just written). The adapter is a\n        // fallback for a patreon-managed user with no persisted row yet (e.g. a\n        // fresh onboard before the first sweep); its tier may be null (lapsed).\n        if ( ! array_key_exists( 'patreon', $out ) ) {\n            $patreon = PatreonSourceReader::readForUser( $wpUserId );\n            if ( $patreon !== null ) {\n                $out['patreon'] = $patreon['tier'];\n            }\n        }\n\n        return $out;\n"]]}
fail=False
for rel,key in TARGETS.items():
    F=os.path.join(ROOT,rel)
    t=open(F,encoding='utf-8').read()
    for i,(old,new) in enumerate(HUNKS[key]):
        if t.count(old)!=1:
            print(f'ABORT {rel}: hunk {i} matched {t.count(old)}x (need 1)'); fail=True; break
        t=t.replace(old,new,1)
    else:
        open(F,'w',encoding='utf-8').write(t); print('patched OK: '+rel); continue
    break
sys.exit(1 if fail else 0)
